// src/components/BackupManual.jsx
import React from "react";
import axios from "axios";
import { RefreshCcw } from "lucide-react";

export default function BackupManual() {
  async function handleManual() {
    try {
      const token = localStorage.getItem('token');
      const res = await axios.post('/api/backup/manual', null, {
        headers: { Authorization: `Bearer ${token}` },
        responseType: 'blob', // <- recebe zip como blob
      });

      // Cria um link temporário p/ baixar o blob
      const blob = new Blob([res.data], { type: 'application/zip' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;

      // tenta nomear o arquivo (opcional)
      const now = new Date().toISOString().replace(/[:.]/g, '-').replace('T','_').slice(0,19);
      a.download = `backup_poliub_${now}.zip`;

      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error(err);
      alert('Falha ao gerar backup.');
    }
  }

  return (
    <div className="pt-4">
      <button
        onClick={handleManual}
        className="bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full flex items-center gap-2"
      >
        <RefreshCcw size={18} /> Fazer backup agora
      </button>
    </div>
  );
}
